	assert.Equal(t.T(), order.ExchangeTypeMarket, marketOrder.ExchangeType)
	assert.Equal(t.T(), order.StatusOpen, marketOrder.Status)
	assert.Equal(t.T(), "", marketOrder.Price.String)

