	assert.Equal(t.T(), false, updatedOrder.IsMaker.Bool)
	assert.Equal(t.T(), order.StatusFilled, updatedOrder.Status)
	assert.Equal(t.T(), "50000.00000000", updatedOrder.TradePrice.String)

	//check the user balance again
