	assert.Equal(t.T(), "0.00000000", updatedBtcUb.FrozenAmount)

	var tradeCount int
	err = t.db.Table("trades AS t").Select("COUNT(t.id)").Scan(&tradeCount).Error
	if err != nil {
		t.Fail(err.Error())
	}
	assert.Equal(t.T(), 2, tradeCount)

	//check trade table
	trade := &order.Trade{}
	err = t.db.Where("sell_order_id = ?", secondLimitOrderID).First(trade).Error
	if err != nil {
		t.Fail(err.Error())
	}
