	assert.Equal(t.T(), "5000.00000000", limitChildOrder.FinalPayedByAmount.String)
	assert.Equal(t.T(), 0.3, limitChildOrder.FeePercentage.Float64)
	assert.Equal(t.T(), true, limitChildOrder.IsMaker.Valid)
	assert.Equal(t.T(), false, limitChildOrder.IsMaker.Bool)
	assert.Equal(t.T(), order.StatusFilled, limitChildOrder.Status)
