	assert.Equal(t.T(), true, limitChildOrder.IsTradedWithBot.Valid)
	assert.Equal(t.T(), true, limitChildOrder.IsTradedWithBot.Bool)
	assert.Equal(t.T(), "50000.00000000", limitChildOrder.TradePrice.String)

	assert.Equal(t.T(), "4900.00000000", updatedSecondLimitOrder.FinalDemandedAmount.String)
	assert.Equal(t.T(), "0.10000000", updatedSecondLimitOrder.FinalPayedByAmount.String)
	assert.Equal(t.T(), 0.3, updatedSecondLimitOrder.FeePercentage.Float64)
	assert.Equal(t.T(), true, updatedSecondLimitOrder.IsMaker.Valid)
	assert.Equal(t.T(), false, updatedSecondLimitOrder.IsMaker.Bool)
	assert.Equal(t.T(), order.StatusFilled, updatedSecondLimitOrder.Status)
	assert.Equal(t.T(), true, updatedSecondLimitOrder.IsTradedWithBot.Valid)
	assert.Equal(t.T(), false, updatedSecondLimitOrder.IsTradedWithBot.Bool)
	assert.Equal(t.T(), "49000.00000000", updatedSecondLimitOrder.TradePrice.String)

	//check both user balances
	firstUserActorUpdatedUsdtUb := &userbalance.UserBalance{}
	err = t.db.Where(userbalance.UserBalance{ID: firstUserActorUsdtUb.ID}).First(firstUserActorUpdatedUsdtUb).Error
