	secondUserActorUpdatedUsdtUb := &userbalance.UserBalance{}
	err = t.db.Where(userbalance.UserBalance{ID: secondUserActorUsdtUb.ID}).First(secondUserActorUpdatedUsdtUb).Error
	if err != nil {
		t.Fail(err.Error())
	}
