	secondUserActorUpdatedBtcUb := &userbalance.UserBalance{}
	err = t.db.Where(userbalance.UserBalance{ID: secondUserActorBtcUb.ID}).First(secondUserActorUpdatedBtcUb).Error
	if err != nil {
		t.Fail(err.Error())
	}

