	assert.Equal(t.T(), "9798.00000000", updatedUsdtUb.Amount)

	updatedBtcUb := &userbalance.UserBalance{}
	err = t.db.Where(userbalance.UserBalance{ID: btcUb.ID}).First(updatedBtcUb).Error
	if err != nil {
		t.Fail(err.Error())
	}
	assert.Equal(t.T(), "0.10280000", updatedBtcUb.Amount)

	//check trade table
