	if err != nil {
		t.Fail(err.Error())
	}

	assert.Equal(t.T(), "0.10000000", secondLimitOrder.DemandedAmount.String)
	assert.Equal(t.T(), "5000.00000000", secondLimitOrder.PayedByAmount.String)
