	req = httptest.NewRequest(http.MethodPost, "/api/v1/order/create", bytes.NewReader(body))
	token = "Bearer " + t.userActor.Token
	req.Header.Set("Authorization", token)
	t.httpServer.ServeHTTP(res, req)

	result = struct {
		Status  bool
		Message string
		Data    order.CreateOrderResponse
	}{}

	//result := response.ApiResponse{}
	err = json.Unmarshal(res.Body.Bytes(), &result)
	if err != nil {
		t.Fail(err.Error())
	}
	assert.Equal(t.T(), http.StatusOK, res.Code)

	assert.Equal(t.T(), "", result.Data.Price)
	marketOrderID := result.Data.ID
	assert.Greater(t.T(), marketOrderID, int64(0))

	marketOrder := &order.Order{}
	err = t.db.Where(order.Order{ID: marketOrderID}).First(marketOrder).Error
	if err != nil {
		t.Fail(err.Error())
	}

	assert.Equal(t.T(), "10000.00000000", marketOrder.DemandedAmount.String)
	assert.Equal(t.T(), "0.20000000", marketOrder.PayedByAmount.String)
	assert.Equal(t.T(), order.TypeSell, marketOrder.Type)
	assert.Equal(t.T(), order.ExchangeTypeMarket, marketOrder.ExchangeType)
