	if err != nil {
		t.Fail(err.Error())
	}

	_, err = t.redisClient.Del(context.Background(), orderBookAskQueue).Result()
	if err != nil {
		t.Fail(err.Error())
	}

	firstUserActor := getNewUserActor()
