	result := struct {
		Status  bool
		Message string
		Data    order.CreateOrderResponse
	}{}

	err = json.Unmarshal(res.Body.Bytes(), &result)
	if err != nil {
		t.Fail(err.Error())
	}
	assert.Equal(t.T(), http.StatusOK, res.Code)
	assert.Equal(t.T(), "50000.00000000", result.Data.Price)
	firstLimitOrderID := result.Data.ID
	assert.Greater(t.T(), firstLimitOrderID, int64(0))

	firstLimitOrder := &order.Order{}
