	if err != nil {
		t.Fail(err.Error())
	}

	assert.Equal(t.T(), "100.00000000", firstLimitOrder.DemandedAmount.String)
	assert.Equal(t.T(), "0.00200000", firstLimitOrder.PayedByAmount.String)
	assert.Equal(t.T(), order.TypeSell, firstLimitOrder.Type)
	assert.Equal(t.T(), order.ExchangeTypeLimit, firstLimitOrder.ExchangeType)
	assert.Equal(t.T(), order.StatusOpen, firstLimitOrder.Status)
	assert.Equal(t.T(), "50000.00000000", firstLimitOrder.Price.String)

	_ = t.engine.SetPostOrderMatchingCall(false) //to be sure the order would be in queue
