	token = "Bearer " + t.userActor.Token
	req.Header.Set("Authorization", token)
	t.httpServer.ServeHTTP(res, req)

	result = struct {
		Status  bool
		Message string
		Data    order.CreateOrderResponse
	}{}

	//result := response.ApiResponse{}
	err = json.Unmarshal(res.Body.Bytes(), &result)
	if err != nil {
		t.Fail(err.Error())
	}
	assert.Equal(t.T(), http.StatusOK, res.Code)

	assert.Equal(t.T(), "", result.Data.Price)
	marketOrderID := result.Data.ID
	assert.Greater(t.T(), marketOrderID, int64(0))

	marketOrder := &order.Order{}
	err = t.db.Where(order.Order{ID: marketOrderID}).First(marketOrder).Error
	if err != nil {
		t.Fail(err.Error())
	}

	assert.Equal(t.T(), "0.00400000", marketOrder.DemandedAmount.String)
	assert.Equal(t.T(), "200.00000000", marketOrder.PayedByAmount.String)
	assert.Equal(t.T(), order.TypeBuy, marketOrder.Type)
	assert.Equal(t.T(), order.ExchangeTypeMarket, marketOrder.ExchangeType)
	assert.Equal(t.T(), order.StatusOpen, marketOrder.Status)
	assert.Equal(t.T(), "", marketOrder.Price.String)

	_ = t.engine.SetPostOrderMatchingCall(true)
	t.engine.Run(1, false)
	time.Sleep(100 * time.Millisecond)
	t.engine.DispatchManually()
	time.Sleep(100 * time.Millisecond)
	t.engine.Stop()
	//end  of market order placement

	//checking updated orders
	updatedFirstLimitOrder := &order.Order{}
	err = t.db.Where(order.Order{ID: firstLimitOrderID}).First(updatedFirstLimitOrder).Error
	if err != nil {
		t.Fail(err.Error())
	}

	updatedSecondLimitOrder := &order.Order{}
	err = t.db.Where(order.Order{ID: secondLimitOrderID}).First(updatedSecondLimitOrder).Error
	if err != nil {
		t.Fail(err.Error())
	}

	secondLimitChildOrder := &order.Order{}
	err = t.db.Where("parent_id = ? ", secondLimitOrderID).First(secondLimitChildOrder).Error
	if err != nil {
		t.Fail(err.Error())
	}

	updatedMarketOrder := &order.Order{}
	err = t.db.Where(order.Order{ID: marketOrderID}).First(updatedMarketOrder).Error
	if err != nil {
		t.Fail(err.Error())
	}

	marketChildOrder := &order.Order{}
	err = t.db.Where("parent_id = ? ", marketOrderID).First(marketChildOrder).Error
	if err != nil {
		t.Fail(err.Error())
	}

	marketSecondChildOrder := &order.Order{}
	err = t.db.Where("parent_id = ? ", marketChildOrder.ID).First(marketSecondChildOrder).Error
	assert.Equal(t.T(), gorm.ErrRecordNotFound, err)

	//check both orders
	assert.Equal(t.T(), "100.00000000", updatedFirstLimitOrder.FinalDemandedAmount.String)
	assert.Equal(t.T(), "0.00200000", updatedFirstLimitOrder.FinalPayedByAmount.String)
	assert.Equal(t.T(), 0.2, updatedFirstLimitOrder.FeePercentage.Float64)
	assert.Equal(t.T(), true, updatedFirstLimitOrder.IsMaker.Valid)
	assert.Equal(t.T(), true, updatedFirstLimitOrder.IsMaker.Bool)
