	assert.Equal(t.T(), "50000.00000000", updatedFirstLimitOrder.TradePrice.String)

	assert.Equal(t.T(), "100.00000000", updatedSecondLimitOrder.FinalDemandedAmount.String)
	assert.Equal(t.T(), "0.00200000", updatedSecondLimitOrder.FinalPayedByAmount.String)
