	assert.Equal(t.T(), true, updatedSecondLimitOrder.IsMaker.Valid)
	assert.Equal(t.T(), true, updatedSecondLimitOrder.IsMaker.Bool)
	assert.Equal(t.T(), order.StatusFilled, updatedSecondLimitOrder.Status)
	assert.Equal(t.T(), "50000.00000000", updatedSecondLimitOrder.TradePrice.String)

