	//call order api
	data = `{"type":"sell","amount":"0.3","exchange_type":"limit","pair_currency_id":1,"price":"50000"}`
	res = httptest.NewRecorder()
	body = []byte(data)
	req = httptest.NewRequest(http.MethodPost, "/api/v1/order/create", bytes.NewReader(body))
	token = "Bearer " + t.userActor.Token
	req.Header.Set("Authorization", token)
	t.httpServer.ServeHTTP(res, req)

	result = struct {
		Status  bool
		Message string
		Data    order.CreateOrderResponse
	}{}

	//result := response.ApiResponse{}
	err = json.Unmarshal(res.Body.Bytes(), &result)
	if err != nil {
		t.Fail(err.Error())
	}
	assert.Equal(t.T(), http.StatusOK, res.Code)

	assert.Equal(t.T(), "50000.00000000", result.Data.Price)
	currentLimitOrderID := result.Data.ID
	assert.Greater(t.T(), currentLimitOrderID, int64(0))

	currentLimitOrder := &order.Order{}
	err = t.db.Where(order.Order{ID: currentLimitOrderID}).First(currentLimitOrder).Error
	if err != nil {
		t.Fail(err.Error())
	}

	assert.Equal(t.T(), "15000.00000000", currentLimitOrder.DemandedAmount.String)
	assert.Equal(t.T(), "0.30000000", currentLimitOrder.PayedByAmount.String)
