	_, err := t.redisClient.Del(context.Background(), allOrdersQueue).Result()
	if err != nil {
		t.Fail(err.Error())
	}

	orderBookBidQueue := engine.OrderBookBidsPrefix + "BTC-USDT"
	orderBookAskQueue := engine.OrderBookAsksPrefix + "BTC-USDT"
