	assert.Equal(t.T(), order.TypeBuy, limitOrder.Type)
	assert.Equal(t.T(), order.ExchangeTypeLimit, limitOrder.ExchangeType)
	assert.Equal(t.T(), order.StatusOpen, limitOrder.Status)
	assert.Equal(t.T(), "50000.00000000", limitOrder.Price.String)

	_ = t.engine.SetPostOrderMatchingCall(false) //to be sure the order would be in queue
